/* ============================== HELPERS ============================== */
const fmt0 = (n) => Math.round(n).toLocaleString("en-IN");
const fmt1 = (n) => (Math.round(n * 10) / 10).toLocaleString("en-IN", { minimumFractionDigits: 1, maximumFractionDigits: 1 });
const fmtCompact = (n) => {
  const abs = Math.abs(n);
  if (abs >= 1e6) return (n / 1e6).toFixed(2) + "M";
  if (abs >= 1e3) return (n / 1e3).toFixed(1) + "k";
  return fmt1(n);
};
const pct = (n, d = 1) => `${n > 0 ? "+" : ""}${n.toFixed(d)}%`;
const MONTH_NAMES = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
const monthLabel = (ym) => {
  const [y, m] = ym.split("-");
  return `${MONTH_NAMES[parseInt(m, 10) - 1]} '${y.slice(2)}`;
};
const monthLabelFull = (ym) => {
  const [y, m] = ym.split("-");
  return `${MONTH_NAMES[parseInt(m, 10) - 1]} ${y}`;
};

const ALL_MONTHS = Array.from(new Set(RAW.monthlyState.map(r => r.m))).sort();
const STATE_LIST = RAW.meta.slice().sort((a, b) => b.total - a.total);
const STATE_STATS_MAP = Object.fromEntries(RAW.stateStats.map(s => [s.s, s]));
const META_MAP = Object.fromEntries(RAW.meta.map(s => [s.state, s]));

function buildMonthlySeries(filterRegion) {
  const byMonth = {};
  ALL_MONTHS.forEach(m => (byMonth[m] = 0));
  RAW.monthlyState.forEach(r => {
    if (filterRegion && filterRegion !== "all" && r.r !== filterRegion) return;
    byMonth[r.m] += r.u;
  });
  return ALL_MONTHS.map(m => ({ m, label: monthLabel(m), u: Math.round(byMonth[m] * 10) / 10 }));
}

function movingAverage(series, key, window) {
  return series.map((pt, i) => {
    const start = Math.max(0, i - window + 1);
    const slice = series.slice(start, i + 1);
    const avg = slice.reduce((a, b) => a + b[key], 0) / slice.length;
    return { ...pt, ma: Math.round(avg * 10) / 10 };
  });
}

