/* ============================== ANIMATED COUNTER ============================== */
function AnimatedNumber({ value, decimals = 0, suffix = "", prefix = "", duration = 1100 }) {
  const [display, setDisplay] = useState(0);
  const raf = useRef(null);
  useEffect(() => {
    const start = performance.now();
    const from = 0;
    const to = value;
    function tick(now) {
      const t = Math.min(1, (now - start) / duration);
      const eased = 1 - Math.pow(1 - t, 3);
      setDisplay(from + (to - from) * eased);
      if (t < 1) raf.current = requestAnimationFrame(tick);
    }
    raf.current = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(raf.current);
  }, [value, duration]);
  const shown = decimals > 0 ? display.toFixed(decimals) : Math.round(display).toLocaleString("en-IN");
  return <span>{prefix}{decimals > 0 ? Number(shown).toLocaleString("en-IN", {minimumFractionDigits: decimals, maximumFractionDigits: decimals}) : shown}{suffix}</span>;
}

