/* ============================== WAVEFORM (signature element) ============================== */
function Waveform({ t, color1, color2, height = 90, amplitude = 22, opacity = 1 }) {
  const id = useRef("wf-" + Math.random().toString(36).slice(2)).current;
  const w = 1200;
  const points = [];
  for (let x = 0; x <= w; x += 6) {
    const y = height / 2 + Math.sin((x / w) * Math.PI * 8) * amplitude * Math.exp(-Math.pow((x - w / 2) / (w * 0.75), 2));
    points.push(`${x},${y.toFixed(1)}`);
  }
  return (
    <svg viewBox={`0 0 ${w} ${height}`} width="100%" height={height} preserveAspectRatio="none" style={{ opacity, display: "block" }}>
      <defs>
        <linearGradient id={id} x1="0" y1="0" x2="1" y2="0">
          <stop offset="0%" stopColor={color1} stopOpacity="0" />
          <stop offset="50%" stopColor={color1} stopOpacity="1" />
          <stop offset="100%" stopColor={color2} stopOpacity="0" />
        </linearGradient>
      </defs>
      <polyline points={points.join(" ")} fill="none" stroke={`url(#${id})`} strokeWidth="2.5"
        strokeDasharray="2000" strokeDashoffset="2000" style={{ animation: "dash 2.4s ease forwards" }} />
    </svg>
  );
}

function GridNodesBackground({ t }) {
  const nodes = useMemo(() => Array.from({ length: 26 }).map((_, i) => ({
    x: Math.random() * 100, y: Math.random() * 100, delay: Math.random() * 3, r: 1.4 + Math.random() * 2,
  })), []);
  return (
    <svg width="100%" height="100%" style={{ position: "absolute", inset: 0 }} preserveAspectRatio="none">
      {nodes.map((n, i) => (
        <circle key={i} cx={`${n.x}%`} cy={`${n.y}%`} r={n.r} fill={i % 2 ? t.amber : t.cyan}
          style={{ animation: `pulseDot 3.4s ease-in-out ${n.delay}s infinite` }} />
      ))}
    </svg>
  );
}

/* ============================== CALENDAR HEATMAP (custom) ============================== */
function CalendarHeatmap({ data, t, year }) {
  const days = data.filter(d => d.d.startsWith(String(year)));
  const map = Object.fromEntries(days.map(d => [d.d, d.u]));
  const max = Math.max(...days.map(d => d.u), 1);
  const start = new Date(`${year}-01-01T00:00:00`);
  const end = new Date(`${year}-12-31T00:00:00`);
  const weeks = [];
  let cur = new Date(start);
  cur.setDate(cur.getDate() - cur.getDay());
  while (cur <= end) {
    const week = [];
    for (let i = 0; i < 7; i++) {
      week.push(new Date(cur));
      cur.setDate(cur.getDate() + 1);
    }
    weeks.push(week);
  }
  const colorFor = (v) => {
    if (v === undefined) return "transparent";
    const ratio = v / max;
    if (ratio === 0) return t.panelBorder;
    const stops = [t.panelBorder, t.cyan + "55", t.cyan + "99", t.amber + "cc", t.amber];
    const idx = Math.min(stops.length - 1, Math.floor(ratio * stops.length));
    return stops[idx];
  };
  return (
    <div style={{ overflowX: "auto" }}>
      <div style={{ display: "flex", gap: 3 }}>
        {weeks.map((week, wi) => (
          <div key={wi} style={{ display: "flex", flexDirection: "column", gap: 3 }}>
            {week.map((d, di) => {
              const key = d.toISOString().slice(0, 10);
              const inYear = d.getFullYear() === year;
              const val = map[key];
              return (
                <div key={di} title={`${key}: ${val !== undefined ? fmt1(val) + " MU" : "no data"}`}
                  style={{ width: 11, height: 11, borderRadius: 3, background: inYear ? colorFor(val) : "transparent",
                    border: inYear && val === undefined ? `1px dashed ${t.panelBorder}` : "none" }} />
              );
            })}
          </div>
        ))}
      </div>
      <div style={{ display: "flex", alignItems: "center", gap: 6, marginTop: 10, fontSize: 11, color: t.textFaint }}>
        Less
        {[t.panelBorder, t.cyan + "55", t.cyan + "99", t.amber + "cc", t.amber].map((c, i) => (
          <div key={i} style={{ width: 11, height: 11, borderRadius: 3, background: c }} />
        ))}
        More
      </div>
    </div>
  );
}

/* ============================== SLOPE CHART (custom) ============================== */
function SlopeChart({ items, t, leftLabel, rightLabel }) {
  const width = 560, height = Math.max(280, items.length * 30 + 40);
  const max = Math.max(...items.flatMap(i => [i.left, i.right])) * 1.08;
  const y = (v) => 20 + (1 - v / max) * (height - 60);
  return (
    <svg viewBox={`0 0 ${width} ${height}`} width="100%" height={height}>
      <text x={40} y={16} fontSize="11" fill={t.textFaint} fontFamily="Inter">{leftLabel}</text>
      <text x={width - 100} y={16} fontSize="11" fill={t.textFaint} fontFamily="Inter">{rightLabel}</text>
      {items.map((it, i) => {
        const up = it.right >= it.left;
        const color = up ? t.green : t.red;
        return (
          <g key={i}>
            <line x1={80} y1={y(it.left)} x2={width - 100} y2={y(it.right)} stroke={color} strokeWidth="2" opacity="0.85" />
            <circle cx={80} cy={y(it.left)} r="3.5" fill={t.textMuted} />
            <circle cx={width - 100} cy={y(it.right)} r="4" fill={color} />
            <text x={10} y={y(it.left) + 4} fontSize="10.5" fill={t.textMuted} fontFamily="Inter">{it.name.slice(0,10)}</text>
            <text x={width - 96} y={y(it.right) + 4} fontSize="10.5" fill={color} fontFamily="JetBrains Mono" fontWeight="600">{it.right.toFixed(0)}</text>
          </g>
        );
      })}
    </svg>
  );
}

/* ============================== HEATMAP GRID (state x month) ============================== */
function StateMonthHeatmap({ t, region }) {
  const states = STATE_LIST.filter(s => region === "all" || s.region === region).slice(0, region === "all" ? 15 : 33);
  const months = ALL_MONTHS;
  const lookup = {};
  RAW.monthlyState.forEach(r => { lookup[`${r.s}|${r.m}`] = r.u; });
  const max = Math.max(...RAW.monthlyState.map(r => r.u));
  const colorFor = (v) => {
    if (!v) return "transparent";
    const ratio = Math.sqrt(v / max);
    const r1 = parseInt(t.cyan.slice(1,3),16), g1=parseInt(t.cyan.slice(3,5),16), b1=parseInt(t.cyan.slice(5,7),16);
    const r2 = parseInt(t.amber.slice(1,3),16), g2=parseInt(t.amber.slice(3,5),16), b2=parseInt(t.amber.slice(5,7),16);
    const r = Math.round(r1+(r2-r1)*ratio), g = Math.round(g1+(g2-g1)*ratio), b = Math.round(b1+(b2-b1)*ratio);
    return `rgba(${r},${g},${b},${0.25+ratio*0.7})`;
  };
  return (
    <div className="scrollx">
      <table style={{ borderCollapse: "collapse", fontSize: 11 }}>
        <thead>
          <tr>
            <th style={{ position: "sticky", left: 0, background: t.panelSolid, padding: "4px 10px", textAlign: "left", color: t.textFaint, fontWeight: 600, zIndex: 1 }}>State</th>
            {months.map(m => <th key={m} style={{ padding: "4px 6px", color: t.textFaint, fontWeight: 500, minWidth: 34 }}>{monthLabel(m)}</th>)}
          </tr>
        </thead>
        <tbody>
          {states.map(s => (
            <tr key={s.state}>
              <td style={{ position: "sticky", left: 0, background: t.panelSolid, padding: "4px 10px", fontWeight: 600, color: t.text, whiteSpace: "nowrap" }}>{s.state}</td>
              {months.map(m => {
                const v = lookup[`${s.state}|${m}`];
                return <td key={m} title={`${s.state} — ${monthLabelFull(m)}: ${v ? fmt1(v) : "—"} MU/day`}
                  style={{ padding: 0 }}>
                  <div style={{ width: 30, height: 22, margin: "1px auto", borderRadius: 4, background: colorFor(v) }} />
                </td>;
              })}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

