/* ============================== TRENDS PAGE ============================== */
function Trends({ t, filters, setFilters }) {
  const series = useMemo(() => movingAverage(buildMonthlySeries(filters.region), "u", 3), [filters.region]);

  const mom = series.map((p, i) => ({
    label: p.label, growth: i === 0 ? 0 : Math.round(((p.u - series[i - 1].u) / series[i - 1].u) * 1000) / 10,
  })).slice(1);

  const yoyPairs = MONTH_NAMES.map((mn, idx) => {
    const m19 = `2019-${String(idx + 1).padStart(2, "0")}`;
    const m20 = `2020-${String(idx + 1).padStart(2, "0")}`;
    const v19 = series.find(s => s.m === m19)?.u || 0;
    const v20 = series.find(s => s.m === m20)?.u || 0;
    return { label: mn, "2019": v19, "2020": v20 };
  });

  const peak = series.reduce((a, b) => (b.u > a.u ? b : a), series[0]);
  const low = series.reduce((a, b) => (b.u < a.u ? b : a), series[0]);
  const biggestDrop = mom.reduce((a, b) => (b.growth < a.growth ? b : a), mom[0]);

  return (
    <div className="fade-in">
      <PageHeader t={t} icon={TrendingUp} title="Overall Consumption Trends" subtitle="Scenario 1 — how national electricity demand moved across the study window." />
      <FilterBar t={t} filters={filters} setFilters={setFilters} />

      <div style={{ marginTop: 20 }}>
        <ChartCard t={t} title="Monthly Demand, Trend & Moving Average" subtitle="Avg daily consumption (MU/day) — annotated for the lockdown and unlock phases" height={360}
          insight={<>Demand peaked in <b>{peak.label}</b> at {fmt1(peak.u)} MU/day and bottomed in <b>{low.label}</b> at {fmt1(low.u)} MU/day — a swing of {fmt1(peak.u - low.u)} MU/day across the study window.</>}>
          <ResponsiveContainer>
            <ComposedChart data={series} margin={{ top: 6, right: 16, left: -6, bottom: 0 }}>
              <defs>
                <linearGradient id="trArea" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="0%" stopColor={t.cyan} stopOpacity={0.3} />
                  <stop offset="100%" stopColor={t.cyan} stopOpacity={0} />
                </linearGradient>
              </defs>
              <CartesianGrid stroke={t.gridLine} vertical={false} />
              <XAxis dataKey="label" tickLine={false} axisLine={false} />
              <YAxis tickLine={false} axisLine={false} width={50} />
              <Tooltip content={<CustomTooltip t={t} />} />
              <ReferenceArea x1={monthLabel("2020-03")} x2={monthLabel("2020-05")} fill={t.red} fillOpacity={0.08} label={{ value: "Lockdown", position: "insideTop", fill: t.red, fontSize: 10 }} />
              <ReferenceLine x={peak.label} stroke={t.green} strokeDasharray="3 3" label={{ value: "Peak", fill: t.green, fontSize: 10, position: "top" }} />
              <ReferenceLine x={low.label} stroke={t.red} strokeDasharray="3 3" label={{ value: "Low", fill: t.red, fontSize: 10, position: "bottom" }} />
              <Area type="monotone" dataKey="u" name="Avg Daily Usage" stroke={t.cyan} fill="url(#trArea)" strokeWidth={2.2} dot={{ r: 2.5 }} />
              <Line type="monotone" dataKey="ma" name="3-mo Moving Avg" stroke={t.amber} strokeWidth={2} dot={false} strokeDasharray="5 4" />
            </ComposedChart>
          </ResponsiveContainer>
        </ChartCard>
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 20, marginTop: 20 }} className="grid-responsive">
        <ChartCard t={t} title="Month-over-Month Growth" subtitle="% change in avg daily demand vs previous month" height={280}
          insight={<>The sharpest single-month contraction was <b>{biggestDrop.label}</b> at {pct(biggestDrop.growth)} month-over-month.</>}>
          <ResponsiveContainer>
            <BarChart data={mom} margin={{ left: -10 }}>
              <CartesianGrid stroke={t.gridLine} vertical={false} />
              <XAxis dataKey="label" tickLine={false} axisLine={false} />
              <YAxis tickLine={false} axisLine={false} width={44} tickFormatter={(v) => `${v}%`} />
              <Tooltip content={<CustomTooltip t={t} unit="%" />} />
              <ReferenceLine y={0} stroke={t.textFaint} />
              <Bar dataKey="growth" name="MoM Growth" radius={[4, 4, 4, 4]}>
                {mom.map((m, i) => <Cell key={i} fill={m.growth >= 0 ? t.green : t.red} />)}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </ChartCard>

        <ChartCard t={t} title="Year-over-Year Comparison" subtitle="2019 vs 2020 avg daily demand, by calendar month" height={280}>
          <ResponsiveContainer>
            <BarChart data={yoyPairs} margin={{ left: -10 }}>
              <CartesianGrid stroke={t.gridLine} vertical={false} />
              <XAxis dataKey="label" tickLine={false} axisLine={false} />
              <YAxis tickLine={false} axisLine={false} width={44} />
              <Tooltip content={<CustomTooltip t={t} />} />
              <Legend iconType="circle" iconSize={8} />
              <Bar dataKey="2019" fill={t.violet} radius={[4, 4, 0, 0]} />
              <Bar dataKey="2020" fill={t.amber} radius={[4, 4, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </ChartCard>
      </div>

      <div style={{ marginTop: 20 }}>
        <InsightBox t={t} tone="cyan" icon={Info}>
          <b>Seasonality note:</b> Demand typically climbs through the pre-monsoon summer (Apr–Jun) as cooling load rises, and again in peak winter for northern states. 2020's summer curve was visibly muted by the lockdown, only re-emerging once industrial and commercial load returned from June onward. From June 2020 the source data shifts to a sparser weekly sampling cadence, so later months reflect fewer observed days per month — all figures above use daily averages, not sums, to keep comparisons fair.
        </InsightBox>
      </div>
    </div>
  );
}

/* ============================== REGIONAL PAGE ============================== */
function Regional({ t }) {
  const [region, setRegion] = useState("all");
  const stackedData = useMemo(() => {
    return ALL_MONTHS.map(m => {
      const row = { label: monthLabel(m) };
      REGION_ORDER.forEach(r => { row[r] = 0; });
      RAW.monthlyState.forEach(s => { if (s.m === m) row[s.r] += s.u; });
      REGION_ORDER.forEach(r => { row[r] = Math.round(row[r] * 10) / 10; });
      return row;
    });
  }, []);

  const regionCards = REGION_ORDER.map(r => {
    const states = STATE_LIST.filter(s => s.region === r);
    const avgDrop = states.reduce((a, s) => a + (STATE_STATS_MAP[s.state]?.dropPct || 0), 0) / states.length;
    const avgRecov = states.reduce((a, s) => a + (STATE_STATS_MAP[s.state]?.recovPct || 0), 0) / states.length;
    return { region: r, total: RAW.regionTotals[r], count: states.length, avgDrop, avgRecov, top: states[0]?.state };
  });

  const treemapData = REGION_ORDER.map(r => ({
    name: REGION_INFO[r].name,
    children: STATE_LIST.filter(s => s.region === r).map(s => ({ name: s.state, size: s.total, color: REGION_INFO[r].color })),
  }));

  const radarData = ["Pre-COVID level", "Lockdown drop", "Recovery strength", "Total share"].map((metric, i) => {
    const row = { metric };
    REGION_ORDER.forEach(r => {
      const states = STATE_LIST.filter(s => s.region === r);
      const preAvg = states.reduce((a, s) => a + (STATE_STATS_MAP[s.state]?.pre || 0), 0);
      const dropAvg = states.reduce((a, s) => a + Math.abs(STATE_STATS_MAP[s.state]?.dropPct || 0), 0) / states.length;
      const recovAvg = states.reduce((a, s) => a + (STATE_STATS_MAP[s.state]?.recovPct || 0), 0) / states.length;
      const share = (RAW.regionTotals[r] / RAW.kpis.totalConsumption) * 100;
      const vals = { "Pre-COVID level": preAvg / 20, "Lockdown drop": dropAvg * 4, "Recovery strength": recovAvg, "Total share": share * 3 };
      row[REGION_INFO[r].name] = Math.round(vals[metric] * 10) / 10;
    });
    return row;
  });

  const bubbleData = STATE_LIST.filter(s => region === "all" || s.region === region).map(s => ({
    x: s.lon, y: s.lat, z: s.total, name: s.state, region: s.region,
    stat: STATE_STATS_MAP[s.state],
  }));

  return (
    <div className="fade-in">
      <PageHeader t={t} icon={MapIcon} title="Regional Variations" subtitle="Scenario 2 — how North, South, East, West and North-East India compare." />

      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(190px,1fr))", gap: 14 }}>
        {regionCards.map(c => (
          <GlassCard key={c.region} className="kpi-card" style={{ "--glow": REGION_INFO[c.region].color, padding: 18 }}>
            <div className="badge" style={{ background: `${REGION_INFO[c.region].color}22`, color: REGION_INFO[c.region].color }}>{REGION_INFO[c.region].name}</div>
            <div className="mono" style={{ fontSize: 21, fontWeight: 700, marginTop: 12 }}>{fmtCompact(c.total)} <span style={{ fontSize: 12, color: t.textFaint }}>MU</span></div>
            <div style={{ fontSize: 11.5, color: t.textMuted, marginTop: 6 }}>{c.count} states · led by {c.top}</div>
            <div style={{ display: "flex", gap: 8, marginTop: 10 }}>
              <StatPill t={t} label="drop" value={pct(c.avgDrop, 1)} positive={c.avgDrop >= 0} />
              <StatPill t={t} label="recov" value={`${c.avgRecov.toFixed(0)}%`} positive={c.avgRecov >= 100} />
            </div>
          </GlassCard>
        ))}
      </div>

      <div style={{ marginTop: 20 }}>
        <ChartCard t={t} title="Consumption by Region Over Time" subtitle="Stacked avg daily demand (MU/day) across all five regions" height={320}>
          <ResponsiveContainer>
            <BarChart data={stackedData} margin={{ left: -10 }}>
              <CartesianGrid stroke={t.gridLine} vertical={false} />
              <XAxis dataKey="label" tickLine={false} axisLine={false} interval={1} />
              <YAxis tickLine={false} axisLine={false} width={50} />
              <Tooltip content={<CustomTooltip t={t} />} />
              <Legend iconType="circle" iconSize={8} formatter={(v) => REGION_INFO[v]?.name || v} />
              {REGION_ORDER.map((r, i) => (
                <Bar key={r} dataKey={r} stackId="a" fill={REGION_INFO[r].color} name={REGION_INFO[r].name}
                  radius={i === REGION_ORDER.length - 1 ? [4, 4, 0, 0] : [0, 0, 0, 0]} />
              ))}
            </BarChart>
          </ResponsiveContainer>
        </ChartCard>
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 20, marginTop: 20 }} className="grid-responsive">
        <ChartCard t={t} title="State Contribution Treemap" subtitle="Sized by total recorded consumption, colored by region" height={320}>
          <ResponsiveContainer>
            <Treemap data={treemapData} dataKey="size" stroke={t.bg} fill={t.amber} aspectRatio={4/3}
              content={<TreemapCell t={t} />} />
          </ResponsiveContainer>
        </ChartCard>
        <ChartCard t={t} title="Regional Profile Radar" subtitle="Normalized comparison across four dimensions" height={320}>
          <ResponsiveContainer>
            <RadarChart data={radarData}>
              <PolarGrid stroke={t.gridLine} />
              <PolarAngleAxis dataKey="metric" tick={{ fill: t.textFaint, fontSize: 10.5 }} />
              <PolarRadiusAxis tick={false} axisLine={false} />
              {REGION_ORDER.map(r => (
                <Radar key={r} name={REGION_INFO[r].name} dataKey={REGION_INFO[r].name} stroke={REGION_INFO[r].color} fill={REGION_INFO[r].color} fillOpacity={0.08} strokeWidth={2} />
              ))}
              <Tooltip content={<CustomTooltip t={t} unit="" />} />
              <Legend iconType="circle" iconSize={8} />
            </RadarChart>
          </ResponsiveContainer>
        </ChartCard>
      </div>

      <div style={{ marginTop: 20 }}>
        <ChartCard t={t} title="Interactive Grid Map" subtitle="Geo-positioned bubble map — size = total consumption, color = region. Hover a node for details." height={420}
          actions={
            <select className="select" value={region} onChange={(e) => setRegion(e.target.value)}>
              <option value="all">All Regions</option>
              {REGION_ORDER.map(r => <option key={r} value={r}>{REGION_INFO[r].name}</option>)}
            </select>
          }>
          <ResponsiveContainer>
            <ScatterChart margin={{ top: 10, right: 20, bottom: 0, left: -10 }}>
              <CartesianGrid stroke={t.gridLine} />
              <XAxis type="number" dataKey="x" name="Longitude" domain={[68, 98]} tickLine={false} axisLine={false} />
              <YAxis type="number" dataKey="y" name="Latitude" domain={[6, 36]} tickLine={false} axisLine={false} />
              <ZAxis type="number" dataKey="z" range={[60, 900]} />
              <Tooltip content={({ active, payload }) => {
                if (!active || !payload?.length) return null;
                const d = payload[0].payload;
                return (
                  <div className="custom-tooltip">
                    <div style={{ fontWeight: 700 }}>{d.name}</div>
                    <div style={{ color: t.textMuted, fontSize: 12 }}>{REGION_INFO[d.region].name} region</div>
                    <div style={{ marginTop: 6 }}>Total: <b>{fmt1(d.z)} MU</b></div>
                    {d.stat && <>
                      <div>Pre-COVID: <b>{fmt1(d.stat.pre)} MU/day</b></div>
                      <div>COVID drop: <b>{pct(d.stat.dropPct)}</b></div>
                      <div>Recovery: <b>{d.stat.recovPct}%</b></div>
                    </>}
                  </div>
                );
              }} />
              {REGION_ORDER.map(r => (
                <Scatter key={r} data={bubbleData.filter(b => b.region === r)} fill={REGION_INFO[r].color} fillOpacity={0.75} name={REGION_INFO[r].name} />
              ))}
            </ScatterChart>
          </ResponsiveContainer>
        </ChartCard>
      </div>

      <div style={{ marginTop: 20 }}>
        <SectionHeading t={t} eyebrow="Detail view" title="State × Month Heatmap" subtitle="Avg daily consumption intensity — darker amber means higher demand that month." />
        <GlassCard style={{ padding: 20 }}>
          <StateMonthHeatmap t={t} region={region} />
        </GlassCard>
      </div>
    </div>
  );
}

function TreemapCell({ x, y, width, height, name, color, depth }) {
  if (depth === 1) return null;
  return (
    <g>
      <rect x={x} y={y} width={width} height={height} style={{ fill: color, stroke: "#0008", strokeWidth: 1.5, opacity: 0.88 }} />
      {width > 44 && height > 22 && (
        <text x={x + 6} y={y + 16} fontSize={10.5} fill="#fff" fontWeight={600} style={{ pointerEvents: "none" }}>{name}</text>
      )}
    </g>
  );
}

/* ============================== RECOVERY PAGE ============================== */
function Recovery({ t }) {
  const k = RAW.kpis;
  const sorted = RAW.stateStats;
  const fastest = sorted.slice(0, 5);
  const slowest = sorted.slice(-5).reverse();

  const nat2020 = buildMonthlySeries("all").filter(p => p.m.startsWith("2020"));
  const slopeItems = STATE_LIST.slice(0, 12).map(s => ({
    name: s.state, left: STATE_STATS_MAP[s.state].pre, right: STATE_STATS_MAP[s.state].recovery,
  }));

  const waterfall = [
    { name: "Pre-Lockdown", value: k.natPre, base: 0, fill: t.cyan },
    { name: "Lockdown Impact", value: Math.abs(k.natLock - k.natPre), base: Math.min(k.natPre, k.natLock), fill: t.red },
    { name: "Lockdown Level", value: k.natLock, base: 0, fill: t.amber },
    { name: "Recovery Gain", value: Math.abs(k.natRec - k.natLock), base: Math.min(k.natLock, k.natRec), fill: t.green },
    { name: "Post-Unlock", value: k.natRec, base: 0, fill: t.violet },
  ];

  const rankAll = sorted.slice().sort((a, b) => b.recovPct - a.recovPct);

  return (
    <div className="fade-in">
      <PageHeader t={t} icon={HeartPulse} title="Recovery After Lockdown" subtitle="Scenario 3 — pre-lockdown, lockdown, and post-unlock demand recovery." />

      <div style={{ marginBottom: 20 }}>
        <PhaseTimeline t={t} />
      </div>

      <ChartCard t={t} title="National Recovery Curve — 2020" subtitle="Avg daily demand across the three COVID phases" height={320}
        insight={<>By the unlock phase, national demand had returned to <b>{k.recoveryIndex}%</b> of its pre-lockdown baseline — effectively a full recovery, with plenty of state-level variation underneath.</>}>
        <ResponsiveContainer>
          <ComposedChart data={nat2020} margin={{ left: -10 }}>
            <CartesianGrid stroke={t.gridLine} vertical={false} />
            <XAxis dataKey="label" tickLine={false} axisLine={false} />
            <YAxis tickLine={false} axisLine={false} width={50} />
            <Tooltip content={<CustomTooltip t={t} />} />
            <ReferenceArea x1={monthLabel("2020-03")} x2={monthLabel("2020-05")} fill={t.red} fillOpacity={0.08} />
            <ReferenceArea x1={monthLabel("2020-06")} x2={monthLabel("2020-12")} fill={t.green} fillOpacity={0.05} />
            <Area type="monotone" dataKey="u" name="Avg Daily Usage" stroke={t.amber} fill={t.amber} fillOpacity={0.18} strokeWidth={2.4} />
          </ComposedChart>
        </ResponsiveContainer>
      </ChartCard>

      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 20, marginTop: 20 }} className="grid-responsive">
        <ChartCard t={t} title="Recovery Slope — Top 12 States" subtitle="Pre-lockdown avg (left) vs post-unlock avg (right), MU/day" height={340}>
          <SlopeChart t={t} items={slopeItems} leftLabel="Pre-Lockdown" rightLabel="Post-Unlock" />
        </ChartCard>
        <ChartCard t={t} title="National Demand Waterfall" subtitle="How avg daily demand moved phase to phase (MU/day)" height={340}>
          <ResponsiveContainer>
            <BarChart data={waterfall} margin={{ left: -10 }}>
              <CartesianGrid stroke={t.gridLine} vertical={false} />
              <XAxis dataKey="name" tickLine={false} axisLine={false} tick={{ fontSize: 10 }} interval={0} />
              <YAxis tickLine={false} axisLine={false} width={50} />
              <Tooltip content={<CustomTooltip t={t} />} formatter={(v) => fmt1(v)} />
              <Bar dataKey="base" stackId="wf" fill="transparent" />
              <Bar dataKey="value" stackId="wf" name="MU/day" radius={[4, 4, 4, 4]}>
                {waterfall.map((w, i) => <Cell key={i} fill={w.fill} />)}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </ChartCard>
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 20, marginTop: 20 }} className="grid-responsive">
        <RankList t={t} title="Fastest Recovering States" subtitle="Highest recovery vs pre-lockdown baseline" items={fastest} good />
        <RankList t={t} title="Slowest Recovering States" subtitle="Lowest recovery vs pre-lockdown baseline" items={slowest} good={false} />
      </div>

      <div style={{ marginTop: 20 }}>
        <SectionHeading t={t} eyebrow="Full ranking" title="Recovery Score by State" subtitle="Post-unlock avg daily demand as a % of each state's pre-lockdown baseline. 100% = full recovery." />
        <GlassCard style={{ padding: 20 }}>
          <div style={{ height: 620, overflowY: "auto" }}>
            <ResponsiveContainer width="100%" height={rankAll.length * 24 + 20}>
              <BarChart data={rankAll} layout="vertical" margin={{ left: 6, right: 40 }}>
                <CartesianGrid stroke={t.gridLine} horizontal={false} />
                <XAxis type="number" domain={[80, 'dataMax + 5']} tickFormatter={(v) => `${v}%`} tickLine={false} axisLine={false} />
                <YAxis type="category" dataKey="s" width={110} tickLine={false} axisLine={false} tick={{ fontSize: 10.5 }} />
                <Tooltip content={<CustomTooltip t={t} unit="%" />} />
                <ReferenceLine x={100} stroke={t.textFaint} />
                <Bar dataKey="recovPct" name="Recovery %" radius={[0, 4, 4, 0]}>
                  {rankAll.map((s, i) => <Cell key={i} fill={s.recovPct >= 100 ? t.green : t.red} />)}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </GlassCard>
      </div>
    </div>
  );
}

function PhaseTimeline({ t }) {
  const phases = [
    { label: "Pre-Lockdown", range: "1 Jan – 24 Mar '20", color: t.cyan },
    { label: "Lockdown", range: "25 Mar – 31 May '20", color: t.red },
    { label: "Unlock 1–5", range: "1 Jun – 30 Sep '20", color: t.amber },
    { label: "Recovery", range: "1 Oct – 5 Dec '20", color: t.green },
  ];
  return (
    <GlassCard style={{ padding: "18px 22px" }}>
      <div style={{ display: "flex", alignItems: "center" }}>
        {phases.map((p, i) => (
          <React.Fragment key={i}>
            <div style={{ flex: 1, textAlign: "center" }}>
              <div style={{ width: 12, height: 12, borderRadius: "50%", background: p.color, margin: "0 auto 8px" }} />
              <div style={{ fontWeight: 700, fontSize: 13 }}>{p.label}</div>
              <div style={{ fontSize: 11, color: t.textFaint, marginTop: 2 }}>{p.range}</div>
            </div>
            {i < phases.length - 1 && <div style={{ flex: 1, height: 2, background: `linear-gradient(90deg, ${p.color}, ${phases[i + 1].color})`, marginBottom: 28 }} />}
          </React.Fragment>
        ))}
      </div>
    </GlassCard>
  );
}

function RankList({ t, title, subtitle, items, good }) {
  return (
    <GlassCard style={{ padding: 20 }}>
      <h3 style={{ margin: 0, fontSize: 15.5, fontWeight: 700 }}>{title}</h3>
      <p style={{ margin: "4px 0 14px", fontSize: 12, color: t.textMuted }}>{subtitle}</p>
      {items.map((s, i) => (
        <div key={s.s} style={{ display: "flex", alignItems: "center", gap: 12, padding: "9px 0", borderBottom: i < items.length - 1 ? `1px solid ${t.panelBorder}` : "none" }}>
          <div className="mono" style={{ width: 22, height: 22, borderRadius: 7, background: t.panel, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 11, fontWeight: 700, color: t.textMuted }}>{i + 1}</div>
          <div style={{ flex: 1 }}>
            <div style={{ fontWeight: 600, fontSize: 13.5 }}>{s.s}</div>
            <div style={{ fontSize: 11, color: t.textFaint }}>{REGION_INFO[s.r].name}</div>
          </div>
          <StatPill t={t} value={`${s.recovPct}%`} positive={good} />
        </div>
      ))}
    </GlassCard>
  );
}

/* ============================== COMPARE PAGE ============================== */
function Compare({ t, bookmarks, toggleBookmark }) {
  const [selected, setSelected] = useState(["Maharashtra", "UP", "Gujarat"]);
  const [search, setSearch] = useState("");
  const filteredList = STATE_LIST.filter(s => s.state.toLowerCase().includes(search.toLowerCase()));

  const toggleSelect = (s) => {
    setSelected(prev => prev.includes(s) ? prev.filter(x => x !== s) : prev.length < 5 ? [...prev, s] : prev);
  };

  const lineData = ALL_MONTHS.map(m => {
    const row = { label: monthLabel(m) };
    selected.forEach(s => {
      const rec = RAW.monthlyState.find(r => r.s === s && r.m === m);
      row[s] = rec ? rec.u : null;
    });
    return row;
  });

  const phaseData = selected.map(s => ({ name: s, Pre: STATE_STATS_MAP[s]?.pre || 0, Lockdown: STATE_STATS_MAP[s]?.lockdown || 0, Recovery: STATE_STATS_MAP[s]?.recovery || 0 }));

  const scatterAll = RAW.stateStats.map(s => ({ x: s.dropPct, y: s.recovPct, name: s.s, region: s.r, sel: selected.includes(s.s) }));

  const radarMetrics = ["Pre-COVID", "Lockdown", "Recovery", "Resilience"];
  const maxPre = Math.max(...RAW.stateStats.map(s => s.pre));
  const radarData = radarMetrics.map(metric => {
    const row = { metric };
    selected.forEach(s => {
      const st = STATE_STATS_MAP[s];
      if (!st) return;
      const vals = { "Pre-COVID": (st.pre / maxPre) * 100, "Lockdown": (st.lockdown / maxPre) * 100, "Recovery": (st.recovery / maxPre) * 100, "Resilience": 100 - Math.abs(st.dropPct) };
      row[s] = Math.round(vals[metric] * 10) / 10;
    });
    return row;
  });

  const monthlyRanking = selected.map(s => {
    const rows = RAW.monthlyState.filter(r => r.s === s);
    const peak = rows.reduce((a, b) => (b.u > a.u ? b : a), rows[0]);
    const lowm = rows.reduce((a, b) => (b.u < a.u ? b : a), rows[0]);
    return { s, peak: peak?.m, peakVal: peak?.u, low: lowm?.m, lowVal: lowm?.u };
  });

  const palette = [t.amber, t.cyan, t.violet, t.pink, t.green];

  return (
    <div className="fade-in">
      <PageHeader t={t} icon={GitCompare} title="State Comparison" subtitle="Pick up to 5 states to compare demand patterns side by side." />

      <GlassCard style={{ padding: 18, marginBottom: 20 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 12 }}>
          <Search size={15} style={{ color: t.textFaint }} />
          <input value={search} onChange={(e) => setSearch(e.target.value)} placeholder="Search a state..."
            style={{ background: "transparent", border: "none", outline: "none", color: t.text, fontSize: 13.5, width: "100%" }} />
        </div>
        <div style={{ display: "flex", gap: 8, flexWrap: "wrap", maxHeight: 130, overflowY: "auto" }}>
          {filteredList.map(s => (
            <div key={s.state} className={`chip ${selected.includes(s.state) ? "active" : ""}`}
              style={{ background: selected.includes(s.state) ? `linear-gradient(135deg, ${t.amber}, #ff8a3d)` : "transparent", display: "flex", alignItems: "center", gap: 6 }}
              onClick={() => toggleSelect(s.state)}>
              {s.state}
              <Star size={11} fill={bookmarks.includes(s.state) ? t.amber : "none"} stroke={bookmarks.includes(s.state) ? t.amber : "currentColor"}
                onClick={(e) => { e.stopPropagation(); toggleBookmark(s.state); }} />
            </div>
          ))}
        </div>
      </GlassCard>

      <ChartCard t={t} title="Monthly Trend Comparison" subtitle="Avg daily consumption (MU/day) across selected states" height={320}>
        <ResponsiveContainer>
          <LineChart data={lineData} margin={{ left: -10 }}>
            <CartesianGrid stroke={t.gridLine} vertical={false} />
            <XAxis dataKey="label" tickLine={false} axisLine={false} />
            <YAxis tickLine={false} axisLine={false} width={50} />
            <Tooltip content={<CustomTooltip t={t} />} />
            <Legend iconType="circle" iconSize={8} />
            {selected.map((s, i) => <Line key={s} type="monotone" dataKey={s} stroke={palette[i]} strokeWidth={2.2} dot={false} connectNulls />)}
          </LineChart>
        </ResponsiveContainer>
      </ChartCard>

      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 20, marginTop: 20 }} className="grid-responsive">
        <ChartCard t={t} title="Phase Comparison" subtitle="Pre / Lockdown / Recovery avg daily demand" height={300}>
          <ResponsiveContainer>
            <BarChart data={phaseData} margin={{ left: -10 }}>
              <CartesianGrid stroke={t.gridLine} vertical={false} />
              <XAxis dataKey="name" tickLine={false} axisLine={false} tick={{ fontSize: 10.5 }} />
              <YAxis tickLine={false} axisLine={false} width={44} />
              <Tooltip content={<CustomTooltip t={t} />} />
              <Legend iconType="circle" iconSize={8} />
              <Bar dataKey="Pre" fill={t.cyan} radius={[4, 4, 0, 0]} />
              <Bar dataKey="Lockdown" fill={t.red} radius={[4, 4, 0, 0]} />
              <Bar dataKey="Recovery" fill={t.green} radius={[4, 4, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </ChartCard>

        <ChartCard t={t} title="Drop vs Recovery Scatter" subtitle="All 33 states — lockdown drop % (x) vs recovery % (y)" height={300}>
          <ResponsiveContainer>
            <ScatterChart margin={{ left: -10 }}>
              <CartesianGrid stroke={t.gridLine} />
              <XAxis type="number" dataKey="x" name="Drop %" unit="%" tickLine={false} axisLine={false} />
              <YAxis type="number" dataKey="y" name="Recovery %" unit="%" tickLine={false} axisLine={false} />
              <Tooltip content={({ active, payload }) => {
                if (!active || !payload?.length) return null;
                const d = payload[0].payload;
                return <div className="custom-tooltip"><b>{d.name}</b><div>Drop: {pct(d.x)}</div><div>Recovery: {d.y}%</div></div>;
              }} />
              <ReferenceLine y={100} stroke={t.textFaint} strokeDasharray="3 3" />
              <Scatter data={scatterAll.filter(d => !d.sel)} fill={t.textFaint} fillOpacity={0.35} />
              <Scatter data={scatterAll.filter(d => d.sel)} fill={t.amber} shape="star" />
            </ScatterChart>
          </ResponsiveContainer>
        </ChartCard>
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 20, marginTop: 20 }} className="grid-responsive">
        <ChartCard t={t} title="Normalized Radar Profile" subtitle="Selected states across four dimensions (0–100 scale)" height={320}>
          <ResponsiveContainer>
            <RadarChart data={radarData}>
              <PolarGrid stroke={t.gridLine} />
              <PolarAngleAxis dataKey="metric" tick={{ fill: t.textFaint, fontSize: 11 }} />
              <PolarRadiusAxis tick={false} axisLine={false} />
              {selected.map((s, i) => <Radar key={s} name={s} dataKey={s} stroke={palette[i]} fill={palette[i]} fillOpacity={0.1} strokeWidth={2} />)}
              <Tooltip content={<CustomTooltip t={t} unit="" />} />
              <Legend iconType="circle" iconSize={8} />
            </RadarChart>
          </ResponsiveContainer>
        </ChartCard>

        <GlassCard style={{ padding: 22 }}>
          <h3 style={{ margin: 0, fontSize: 16, fontWeight: 700 }}>Monthly Ranking</h3>
          <p style={{ margin: "4px 0 14px", fontSize: 12, color: t.textMuted }}>Peak and lowest month per selected state</p>
          <table className="table-clean">
            <thead><tr><th>State</th><th>Peak Month</th><th>Lowest Month</th></tr></thead>
            <tbody>
              {monthlyRanking.map(r => (
                <tr key={r.s}>
                  <td style={{ fontWeight: 600 }}>{r.s}</td>
                  <td><span style={{ color: t.green, fontWeight: 600 }}>{r.peak ? monthLabelFull(r.peak) : "—"}</span></td>
                  <td><span style={{ color: t.red, fontWeight: 600 }}>{r.low ? monthLabelFull(r.low) : "—"}</span></td>
                </tr>
              ))}
            </tbody>
          </table>
        </GlassCard>
      </div>

      <div style={{ marginTop: 20 }}>
        <SectionHeading t={t} eyebrow="Daily rhythm" title="National Daily Consumption Calendar — 2020" subtitle="GitHub-style heatmap of national daily demand. Blank cells mean no reading was recorded that day." />
        <GlassCard style={{ padding: 20 }}>
          <CalendarHeatmap t={t} data={RAW.dailyNational} year={2020} />
        </GlassCard>
      </div>
    </div>
  );
}

/* ============================== COVID IMPACT PAGE ============================== */
function CovidImpact({ t }) {
  const k = RAW.kpis;
  const stats = RAW.stateStats;

  const highestIncrease = stats.slice().sort((a, b) => b.recovPct - a.recovPct)[0];
  const highestDecrease = stats.slice().sort((a, b) => a.recovPct - b.recovPct)[0];
  const mostStable = stats.slice().sort((a, b) => Math.abs(a.dropPct) - Math.abs(b.dropPct))[0];
  const mostVolatile = stats.slice().sort((a, b) => (Math.abs(b.dropPct) + Math.abs(b.recovPct - 100)) - (Math.abs(a.dropPct) + Math.abs(a.recovPct - 100)))[0];

  const regionBars = REGION_ORDER.map(r => {
    const states = stats.filter(s => s.r === r);
    return {
      name: REGION_INFO[r].name,
      drop: Math.round((states.reduce((a, s) => a + s.dropPct, 0) / states.length) * 10) / 10,
      recov: Math.round((states.reduce((a, s) => a + s.recovPct, 0) / states.length) * 10) / 10,
      color: REGION_INFO[r].color,
    };
  });

  const avgLoss = k.natPre - k.natLock;

  return (
    <div className="fade-in">
      <PageHeader t={t} icon={ShieldAlert} title="COVID-19 Impact Analysis" subtitle="Before → during → recovery, quantified nationally and by state." />

      <div style={{ display: "grid", gridTemplateColumns: "1fr auto 1fr auto 1fr", gap: 14, alignItems: "center", marginBottom: 22 }} className="grid-responsive">
        <PhaseCard t={t} label="Before Lockdown" value={`${fmt1(k.natPre)} MU/day`} sub="1 Jan – 24 Mar 2020" color={t.cyan} />
        <ArrowRight size={22} style={{ color: t.textFaint, justifySelf: "center" }} className="hide-mobile" />
        <PhaseCard t={t} label="During Lockdown" value={`${fmt1(k.natLock)} MU/day`} sub="25 Mar – 31 May 2020" color={t.red} badge={pct(k.covidImpact)} />
        <ArrowRight size={22} style={{ color: t.textFaint, justifySelf: "center" }} className="hide-mobile" />
        <PhaseCard t={t} label="Recovery" value={`${fmt1(k.natRec)} MU/day`} sub="1 Jun – 5 Dec 2020" color={t.green} badge={`${k.recoveryIndex}%`} />
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(200px,1fr))", gap: 16 }}>
        {[
          { label: "Percentage Drop", value: pct(k.covidImpact), icon: TrendingDown, tone: "red" },
          { label: "Percentage Recovery", value: `${k.recoveryIndex}%`, icon: TrendingUp, tone: "green" },
          { label: "Average Loss", value: `${fmt1(avgLoss)} MU/day`, icon: Gauge, tone: "amber" },
          { label: "Demand Recovery Rate", value: `${k.recoveryIndex}% of baseline`, icon: HeartPulse, tone: "cyan" },
        ].map((c, i) => (
          <GlassCard key={i} className="kpi-card" style={{ "--glow": t[c.tone], padding: 18 }}>
            <c.icon size={17} style={{ color: t[c.tone] }} />
            <div className="mono" style={{ fontSize: 21, fontWeight: 700, marginTop: 12 }}>{c.value}</div>
            <div style={{ fontSize: 12, color: t.textMuted, marginTop: 4, fontWeight: 600 }}>{c.label}</div>
          </GlassCard>
        ))}
      </div>

      <div style={{ marginTop: 20 }}>
        <ChartCard t={t} title="Regional Drop vs Recovery" subtitle="Average lockdown drop % and recovery % by region" height={300}>
          <ResponsiveContainer>
            <BarChart data={regionBars} margin={{ left: -10 }}>
              <CartesianGrid stroke={t.gridLine} vertical={false} />
              <XAxis dataKey="name" tickLine={false} axisLine={false} />
              <YAxis tickLine={false} axisLine={false} width={44} />
              <Tooltip content={<CustomTooltip t={t} unit="%" />} />
              <Legend iconType="circle" iconSize={8} />
              <ReferenceLine y={0} stroke={t.textFaint} />
              <Bar dataKey="drop" name="Avg Drop %" fill={t.red} radius={[4, 4, 0, 0]} />
              <Bar dataKey="recov" name="Avg Recovery %" fill={t.green} radius={[4, 4, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </ChartCard>
      </div>

      <div style={{ marginTop: 20 }}>
        <SectionHeading t={t} eyebrow="Automated analysis" title="Advanced Insights" subtitle="Generated directly from the state-level recovery statistics." />
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(260px,1fr))", gap: 16 }}>
          <InsightCard t={t} icon={TrendingUp} tone="green" title="Highest Increase"
            body={<>{highestIncrease.s} posted the strongest rebound, reaching <b>{highestIncrease.recovPct}%</b> of its pre-lockdown baseline during the recovery phase.</>} />
          <InsightCard t={t} icon={TrendingDown} tone="red" title="Highest Decrease"
            body={<>{highestDecrease.s} recovered the least, settling at just <b>{highestDecrease.recovPct}%</b> of pre-lockdown demand by December.</>} />
          <InsightCard t={t} icon={CheckCircle2} tone="cyan" title="Most Stable State"
            body={<>{mostStable.s} barely moved through the lockdown, with only a <b>{pct(mostStable.dropPct)}</b> change — the flattest curve in the dataset.</>} />
          <InsightCard t={t} icon={AlertTriangle} tone="amber" title="Most Volatile State"
            body={<>{mostVolatile.s} swung the hardest across phases, combining a {pct(mostVolatile.dropPct)} lockdown move with a {mostVolatile.recovPct}% recovery level.</>} />
          <InsightCard t={t} icon={MapIcon} tone="violet" title="Regional Growth Differences"
            body={<>{[...regionBars].sort((a,b)=>b.recov-a.recov)[0].name} India recovered fastest on average, while {[...regionBars].sort((a,b)=>a.recov-b.recov)[0].name} India lagged — regional industrial mix likely explains much of the gap.</>} />
          <InsightCard t={t} icon={ShieldAlert} tone="red" title="Lockdown Impact Summary"
            body={<>Nationally, demand fell {pct(k.covidImpact)} during the lockdown — a modest dip in aggregate, since industrial shutdowns were partly offset by rising residential consumption as households stayed home.</>} />
        </div>
      </div>
    </div>
  );
}

function PhaseCard({ t, label, value, sub, color, badge }) {
  return (
    <GlassCard style={{ padding: 20, textAlign: "center" }}>
      <div style={{ fontSize: 11.5, fontWeight: 700, textTransform: "uppercase", letterSpacing: ".05em", color }}>{label}</div>
      <div className="mono" style={{ fontSize: 22, fontWeight: 700, marginTop: 10 }}>{value}</div>
      <div style={{ fontSize: 11.5, color: t.textFaint, marginTop: 4 }}>{sub}</div>
      {badge && <div className="badge" style={{ marginTop: 10, background: `${color}20`, color }}>{badge}</div>}
    </GlassCard>
  );
}

function InsightCard({ t, icon: Icon, tone, title, body }) {
  return (
    <GlassCard style={{ padding: 20 }}>
      <div style={{ display: "flex", gap: 12, alignItems: "flex-start" }}>
        <div style={{ width: 34, height: 34, borderRadius: 10, background: `${t[tone]}20`, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
          <Icon size={16} style={{ color: t[tone] }} />
        </div>
        <div>
          <div style={{ fontWeight: 700, fontSize: 14 }}>{title}</div>
          <p style={{ margin: "6px 0 0", fontSize: 12.8, color: t.textMuted, lineHeight: 1.6 }}>{body}</p>
        </div>
      </div>
    </GlassCard>
  );
}

/* ============================== REPORTS PAGE ============================== */
function toCSV(rows, headers) {
  const esc = (v) => (typeof v === "string" && v.includes(",")) ? `"${v}"` : v;
  return [headers.join(","), ...rows.map(r => headers.map(h => esc(r[h])).join(","))].join("\n");
}
function download(filename, text) {
  const blob = new Blob([text], { type: "text/csv;charset=utf-8;" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url; a.download = filename; document.body.appendChild(a); a.click();
  document.body.removeChild(a); URL.revokeObjectURL(url);
}

function Reports({ t }) {
  const exportMonthly = () => {
    const rows = RAW.monthlyState.map(r => ({ State: r.s, Region: REGION_INFO[r.r].name, Month: r.m, "AvgDailyUsageMU": r.u }));
    download("electricity_monthly_state.csv", toCSV(rows, ["State", "Region", "Month", "AvgDailyUsageMU"]));
  };
  const exportRecovery = () => {
    const rows = RAW.stateStats.map(r => ({ State: r.s, Region: REGION_INFO[r.r].name, PreLockdownMUday: r.pre, LockdownMUday: r.lockdown, RecoveryMUday: r.recovery, DropPct: r.dropPct, RecoveryPct: r.recovPct }));
    download("electricity_recovery_stats.csv", toCSV(rows, ["State", "Region", "PreLockdownMUday", "LockdownMUday", "RecoveryMUday", "DropPct", "RecoveryPct"]));
  };
  const exportDaily = () => {
    const rows = RAW.dailyNational.map(r => ({ Date: r.d, NationalTotalMU: r.u }));
    download("electricity_daily_national.csv", toCSV(rows, ["Date", "NationalTotalMU"]));
  };

  return (
    <div className="fade-in">
      <PageHeader t={t} icon={FileDown} title="Reports & Export" subtitle="Download the underlying figures behind every chart in this dashboard." />
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(260px,1fr))", gap: 18 }}>
        {[
          { title: "Monthly State Data", desc: "Avg daily consumption per state, per month — 792 rows.", action: exportMonthly, icon: BarChart3 },
          { title: "Recovery Statistics", desc: "Pre-lockdown, lockdown & recovery figures for all 33 states.", action: exportRecovery, icon: HeartPulse },
          { title: "National Daily Series", desc: "Daily national total consumption — every recorded date.", action: exportDaily, icon: Activity },
        ].map((c, i) => (
          <GlassCard key={i} style={{ padding: 22 }}>
            <c.icon size={20} style={{ color: t.amber }} />
            <h3 style={{ margin: "12px 0 4px", fontSize: 15.5 }}>{c.title}</h3>
            <p style={{ margin: 0, fontSize: 12.5, color: t.textMuted, lineHeight: 1.6, minHeight: 38 }}>{c.desc}</p>
            <div className="btn btn-primary" style={{ marginTop: 14, width: "fit-content" }} onClick={c.action}><Download size={14} /> Export CSV</div>
          </GlassCard>
        ))}
      </div>

      <div style={{ marginTop: 24 }}>
        <InsightBox t={t} tone="cyan" icon={Info}>
          Exports reflect the currently computed figures shown across the dashboard (avg daily MU, not raw sums), so numbers line up exactly with what you see in the charts.
        </InsightBox>
      </div>
    </div>
  );
}

/* ============================== SETTINGS PAGE ============================== */
function SettingsPage({ t, mode, setMode }) {
  return (
    <div className="fade-in">
      <PageHeader t={t} icon={SettingsIcon} title="Settings" subtitle="Display preferences and methodology notes." />
      <GlassCard style={{ padding: 22, marginBottom: 18 }}>
        <h3 style={{ margin: 0, fontSize: 15.5 }}>Appearance</h3>
        <p style={{ margin: "4px 0 14px", fontSize: 12.5, color: t.textMuted }}>Switch between the control-room dark theme and a bright analyst-desk light theme.</p>
        <Segmented t={t} value={mode} onChange={setMode} options={[{ value: "dark", label: "Dark" }, { value: "light", label: "Light" }]} />
      </GlassCard>
      <GlassCard style={{ padding: 22 }}>
        <h3 style={{ margin: 0, fontSize: 15.5 }}>Methodology notes</h3>
        <ul style={{ margin: "12px 0 0", paddingLeft: 18, color: t.textMuted, fontSize: 13, lineHeight: 1.9 }}>
          <li>All figures are in <b>Million Units (MU)</b> of electricity, as recorded in the source dataset.</li>
          <li>The source data samples roughly daily through May 2020, then shifts to about one reading per week — every chart uses <b>average-per-day</b>, not raw sums, so monthly figures stay comparable across that shift.</li>
          <li>Lockdown phases follow India's official timeline: Pre-lockdown (1 Jan – 24 Mar 2020), Lockdown (25 Mar – 31 May 2020), Unlock/Recovery (1 Jun – 5 Dec 2020).</li>
          <li>Recovery % compares each state's average daily demand in the recovery window against its own pre-lockdown baseline.</li>
        </ul>
      </GlassCard>
    </div>
  );
}

/* ============================== SIDEBAR ============================== */
const NAV_ITEMS = [
  { key: "overview", label: "Dashboard", icon: LayoutDashboard },
  { key: "trends", label: "Overall Trends", icon: TrendingUp },
  { key: "regional", label: "Regional Analysis", icon: MapIcon },
  { key: "recovery", label: "Recovery Analysis", icon: HeartPulse },
  { key: "compare", label: "State Comparison", icon: GitCompare },
  { key: "covid", label: "COVID Impact", icon: ShieldAlert },
  { key: "reports", label: "Reports", icon: FileDown },
  { key: "settings", label: "Settings", icon: SettingsIcon },
];

function Sidebar({ t, page, setPage, open, setOpen, mode, setMode }) {
  return (
    <>
      {open && <div onClick={() => setOpen(false)} style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,.5)", zIndex: 40 }} className="hide-mobile-inv" />}
      <div style={{
        position: "fixed", top: 0, bottom: 0, left: 0, width: 244, zIndex: 41,
        transform: open ? "translateX(0)" : undefined,
        display: "flex", flexDirection: "column", padding: "22px 14px",
        background: t.panelSolid, borderRight: `1px solid ${t.panelBorder}`,
      }} className={`sidebar-fixed ${open ? "sidebar-open" : ""}`}>
        <div style={{ display: "flex", alignItems: "center", gap: 10, padding: "4px 10px 22px" }}>
          <div style={{ width: 34, height: 34, borderRadius: 10, background: `linear-gradient(135deg, ${t.amber}, ${t.cyan})`, display: "flex", alignItems: "center", justifyContent: "center" }}>
            <Zap size={17} color="#0b0d12" />
          </div>
          <div>
            <div style={{ fontWeight: 700, fontSize: 14.5, fontFamily: "'Space Grotesk',sans-serif" }}>GridPulse</div>
            <div style={{ fontSize: 10, color: t.textFaint }}>India Electricity Analytics</div>
          </div>
        </div>
        <div style={{ display: "flex", flexDirection: "column", gap: 3, flex: 1, overflowY: "auto" }}>
          {NAV_ITEMS.map(item => (
            <div key={item.key} className={`sidebar-item ${page === item.key ? "active" : ""}`}
              onClick={() => { setPage(item.key); setOpen(false); }}>
              <item.icon size={16} /> {item.label}
            </div>
          ))}
        </div>
        <div className="sidebar-item" onClick={() => setPage("landing")} style={{ marginTop: 8 }}>
          <ChevronRight size={16} style={{ transform: "rotate(180deg)" }} /> Back to Landing
        </div>
        <div style={{ marginTop: 12, padding: "12px 10px", borderRadius: 14, background: t.panel, display: "flex", alignItems: "center", justifyContent: "space-between" }}>
          <span style={{ fontSize: 11.5, color: t.textMuted, fontWeight: 600 }}>Theme</span>
          <div onClick={() => setMode(mode === "dark" ? "light" : "dark")} style={{ cursor: "pointer", width: 30, height: 30, borderRadius: 9, display: "flex", alignItems: "center", justifyContent: "center", background: t.panelSolid }}>
            {mode === "dark" ? <Moon size={14} style={{ color: t.cyan }} /> : <Sun size={14} style={{ color: t.amber }} />}
          </div>
        </div>
      </div>
    </>
  );
}

function TopBar({ t, setOpen, page, bookmarks }) {
  const currentItem = NAV_ITEMS.find(i => i.key === page);
  return (
    <div className="hide-desktop" style={{ display: "none", alignItems: "center", justifyContent: "space-between", padding: "14px 18px", position: "sticky", top: 0, zIndex: 30, background: t.panelSolid, borderBottom: `1px solid ${t.panelBorder}` }}>
      <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
        <div onClick={() => setOpen(true)} style={{ cursor: "pointer" }}><Menu size={20} /></div>
        <span style={{ fontWeight: 700, fontSize: 14 }}>{currentItem?.label || "GridPulse"}</span>
      </div>
      {bookmarks.length > 0 && <StatPill t={t} label="saved" value={bookmarks.length} />}
    </div>
  );
}

/* ============================== APP ROOT ============================== */
export default function App() {
  const [mode, setMode] = useState("dark");
  const [page, setPage] = useState("landing");
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [filters, setFilters] = useState({ year: "all", region: "all" });
  const [bookmarks, setBookmarks] = useState([]);
  const t = THEME[mode];

  useEffect(() => {
    (async () => {
      try {
        const res = await window.storage?.get?.("gridpulse:bookmarks", false);
        if (res?.value) setBookmarks(JSON.parse(res.value));
      } catch (e) { /* no saved bookmarks yet */ }
    })();
  }, []);

  const toggleBookmark = useCallback((state) => {
    setBookmarks(prev => {
      const next = prev.includes(state) ? prev.filter(s => s !== state) : [...prev, state];
      (async () => { try { await window.storage?.set?.("gridpulse:bookmarks", JSON.stringify(next), false); } catch (e) {} })();
      return next;
    });
  }, []);

  const goto = (p) => { setPage(p); window.scrollTo({ top: 0, behavior: "smooth" }); };

  const isLanding = page === "landing";

  return (
    <div className="ecai-root" style={{ position: "relative" }}>
      <GlobalStyles t={t} />
      <style>{`
        .sidebar-fixed { transition: transform .3s ease; }
        @media (max-width: 880px) {
          .sidebar-fixed { transform: translateX(-100%); }
          .sidebar-fixed.sidebar-open { transform: translateX(0); }
          .hide-desktop { display: flex !important; }
          .app-main { margin-left: 0 !important; }
        }
      `}</style>

      {isLanding ? (
        <div>
          <div style={{ position: "fixed", top: 20, right: 24, zIndex: 20, display: "flex", gap: 10 }}>
            <div className="btn" onClick={() => setMode(mode === "dark" ? "light" : "dark")}>
              {mode === "dark" ? <Moon size={15} /> : <Sun size={15} />}
            </div>
          </div>
          <Landing t={t} goto={goto} />
        </div>
      ) : (
        <div style={{ display: "flex" }}>
          <Sidebar t={t} page={page} setPage={goto} open={sidebarOpen} setOpen={setSidebarOpen} mode={mode} setMode={setMode} />
          <div className="app-main" style={{ marginLeft: 244, flex: 1, minWidth: 0 }}>
            <TopBar t={t} setOpen={setSidebarOpen} page={page} bookmarks={bookmarks} />
            <div style={{ padding: "30px clamp(16px, 3vw, 40px) 60px", maxWidth: 1400, margin: "0 auto" }}>
              {page === "overview" && <Overview t={t} filters={filters} setFilters={setFilters} />}
              {page === "trends" && <Trends t={t} filters={filters} setFilters={setFilters} />}
              {page === "regional" && <Regional t={t} />}
              {page === "recovery" && <Recovery t={t} />}
              {page === "compare" && <Compare t={t} bookmarks={bookmarks} toggleBookmark={toggleBookmark} />}
              {page === "covid" && <CovidImpact t={t} />}
              {page === "reports" && <Reports t={t} />}
              {page === "settings" && <SettingsPage t={t} mode={mode} setMode={setMode} />}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
